const stacks = [
  "React", "Node.js", "Python", "Go", "Rust", "TypeScript", "AWS", "DevOps",
  "ML Engineer", "Data Engineer", "Java", "Kubernetes", "Docker", "Vue.js",
  "Angular", "PHP", "Ruby", "C++", "Swift", "Kotlin"
];

const staticData = $getWorkflowStaticData('global');
staticData.rawJobs = [];

return stacks.map(function (stack) { return { json: { stack: stack } }; });

const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.rawJobs)) staticData.rawJobs = [];

const stack = $('Loop Over Tech Stacks').item.json.stack;
const response = $input.first().json;
const jobs = Array.isArray(response && response.jobs) ? response.jobs : [];

for (const job of jobs) {
  staticData.rawJobs.push(Object.assign({}, job, { _searchedStack: stack }));
}

return [{ json: { stack: stack, jobsFound: jobs.length } }];

const staticData = $getWorkflowStaticData('global');
const rawJobs = Array.isArray(staticData.rawJobs) ? staticData.rawJobs : [];

function generateUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

function toIso(value) {
  if (!value) return null;
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d.toISOString();
}

const seen = new Set();
const deduped = [];

for (const raw of rawJobs) {
  try {
    const link = (raw && raw.link) || '';
    const company = (raw && raw.company) || '';
    const key = link + '||' + company;
    if (seen.has(key)) continue;
    seen.add(key);

    deduped.push({
      id: generateUuid(),
      title: (raw && raw.title) || null,
      company: (raw && raw.company) || null,
      location: (raw && raw.location) || null,
      stack: [raw && raw._searchedStack].filter(Boolean),
      date_posted: toIso(raw && raw.date_posted),
      link: (raw && raw.link) || null,
      source: (raw && raw.source) || 'serp',
      type: (raw && raw.type) || 'full-time',
      created_at: new Date().toISOString()
    });
  } catch (err) {
    continue;
  }
}

return deduped.map(function (job) { return { json: job }; });
